import axios from 'axios';

const API_URL = '/api/forum';

// Get all forum posts with optional filtering
const getAllPosts = async (category = '', sort = 'latest') => {
  let url = `${API_URL}/posts`;
  
  const params = new URLSearchParams();
  if (category) params.append('category', category);
  if (sort) params.append('sort', sort);
  
  const queryString = params.toString();
  if (queryString) url += `?${queryString}`;
  
  const response = await axios.get(url);
  return response.data;
};

// Get a single post by ID
const getPostById = async (postId) => {
  const response = await axios.get(`${API_URL}/posts/${postId}`);
  return response.data;
};

// Create a new forum post
const createPost = async (postData) => {
  const response = await axios.post(`${API_URL}/posts`, postData);
  return response.data;
};

// Update a forum post
const updatePost = async (postId, postData) => {
  const response = await axios.put(`${API_URL}/posts/${postId}`, postData);
  return response.data;
};

// Delete a forum post
const deletePost = async (postId) => {
  const response = await axios.delete(`${API_URL}/posts/${postId}`);
  return response.data;
};

// Like or unlike a post
const togglePostLike = async (postId) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/like`);
  return response.data;
};

// Get all comments for a post
const getComments = async (postId) => {
  const response = await axios.get(`${API_URL}/posts/${postId}/comments`);
  return response.data;
};

// Add a comment to a post
const addComment = async (postId, commentData) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/comments`, commentData);
  return response.data;
};

// Update a comment
const updateComment = async (postId, commentId, commentData) => {
  const response = await axios.put(`${API_URL}/posts/${postId}/comments/${commentId}`, commentData);
  return response.data;
};

// Delete a comment
const deleteComment = async (postId, commentId) => {
  const response = await axios.delete(`${API_URL}/posts/${postId}/comments/${commentId}`);
  return response.data;
};

// Like or unlike a comment
const toggleCommentLike = async (postId, commentId) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/comments/${commentId}/like`);
  return response.data;
};

// Search forum posts
const searchPosts = async (searchTerm) => {
  const response = await axios.get(`${API_URL}/search?q=${encodeURIComponent(searchTerm)}`);
  return response.data;
};

// Get posts by user
const getUserPosts = async (userId) => {
  const response = await axios.get(`${API_URL}/users/${userId}/posts`);
  return response.data;
};

// Report a post
const reportPost = async (postId, reportData) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/report`, reportData);
  return response.data;
};

// Report a comment
const reportComment = async (postId, commentId, reportData) => {
  const response = await axios.post(`${API_URL}/posts/${postId}/comments/${commentId}/report`, reportData);
  return response.data;
};

const forumService = {
  getAllPosts,
  getPostById,
  createPost,
  updatePost,
  deletePost,
  togglePostLike,
  getComments,
  addComment,
  updateComment,
  deleteComment,
  toggleCommentLike,
  searchPosts,
  getUserPosts,
  reportPost,
  reportComment
};

export default forumService;
